{"path": "/tmp/sv-6050002cef0c4865894b2923dfef48e1/Components/Catalog/ProductCard.razor", "file_text": "<div class="card h-100 product-card @(Product.InStock ? "" : "out-of-stock")"
     @onclick="HandleCardClick"
     role="button">
    <div class="card-img-top placeholder-image d-flex align-items-center justify-content-center bg-light"
         style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h5 class="card-title text-truncate" title="@Product.Name">@Product.Name</h5>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarRating(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        int empty = 5 - filled;
        return new string('★', filled) + new string('☆', empty);
    }
}
"}

{"path": "/tmp/sv-6050002cef0c4865894b2923dfef48e1/Components/Catalog/CatalogFilters.razor", "file_text": "<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Categories</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@IsSelected(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Min Price</label>
        <input type="number" class="form-control" min="0" step="0.01"
               value="@_minPrice" @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Max Price</label>
        <input type="number" class="form-control" min="0" step="0.01"
               value="@_maxPrice" @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@_inStockOnly" @onchange="@(e => _inStockOnly = (bool)e.Value!)" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    [Parameter]
    public EventCallback OnClearFilters { get; set; }

    private List<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
        {
            if (!_selectedCategories.Contains(category))
                _selectedCategories.Add(category);
        }
        else
        {
            _selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? new List<string>(_selectedCategories) : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnClearFilters.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

{"path": "/tmp/sv-6050002cef0c4865894b2923dfef48e1/Components/Catalog/CatalogToolbar.razor", "file_text": "<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <label class="form-label me-2 mb-0" for="sortSelect">Sort by:</label>
        <select id="sortSelect" class="form-select d-inline-block w-auto"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
        else
        {
            <span>No products found</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}
"}

