@page "/catalog"
@rendermode InteractiveServer
@using sv_6050002cef0c4865894b2923dfef48e1.Components.Catalog
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-3 mb-4">
            <CatalogFilters Categories="@_categories"
                            OnApplyFilters="HandleApplyFilters"
                            OnClearFilters="HandleClearFilters" />
        </div>

        <div class="col-lg-9">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <h4 class="text-muted">No products found</h4>
                    <p class="text-muted">Try adjusting your filters.</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="@_result.TotalCount"
                                Page="@_result.Page"
                                PageSize="@_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <div class="row row-cols-1 row-cols-md-2 row-cols-xl-3 g-4">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="@product"
                                         OnSelected="HandleProductSelected"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                <CatalogPagination CurrentPage="@_currentPage"
                                   TotalPages="@_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            _result = productsTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;
        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Add to cart logic would go here
        return Task.CompletedTask;
    }
}

